[malfet]: Here is a small  example of sticky errors triggered by on-device assert:

```cpp
#include <stdio.h>
#include <assert.h>

__global__ void assert_kernel() {
  assert (threadIdx.x % 5 != 4);
}

bool test_alloc() {
  void *gpu_vec = nullptr;

  return cudaMalloc(&gpu_vec, 11) == cudaSuccess;
}

bool test_assert() {
  assert_kernel<<<1, 6>>>();
  return cudaDeviceSynchronize() != cudaSuccess;
}

int main(int argc, const char*argv[]) {
  if (argc > 1) {
    printf("test_alloc() %s\n", test_alloc() ? "succeeded" : "failed");
    printf("test_assert() %s\n", test_assert() ? "succeeded" : "failed");
    return 0;
  }
  printf("test_assert() %s\n", test_assert() ? "succeeded" : "failed");
  printf("test_alloc() %s\n", test_alloc() ? "succeeded" : "failed");
  return 0;
}
```
If launched without any argument, it would report that both tests have failed (since test_assert() introduce a non-recoverable error), but if launched with the argument both tests will pass (since `test_assert` is executed at the very end)

